mapper.select:
SELECT f.id, f.question_id, LEFT(q.content, 60) AS question_summary, f.type, CASE f.type WHEN 1 THEN '答案错误' WHEN 2 THEN '题干歧义' WHEN 3 THEN '解析不清' WHEN 4 THEN '排版问题' ELSE '其他' END AS type_label, f.status, CASE f.status WHEN 0 THEN '待处理' WHEN 1 THEN '已采纳' WHEN 2 THEN '已驳回' WHEN 3 THEN '已修复' ELSE '未知' END AS status_label, f.description, f.created_at, f.replied_at FROM t_question_feedback f LEFT JOIN t_question q ON f.question_id = q.id
f.status = #{status}
ORDER BY CASE WHEN f.status = 0 THEN 0 ELSE 1 END, f.created_at DESC
